css:
@page {
    size: A4;
    margin: 1cm;
}

.receipt-container {
    font-family: Arial, sans-serif;
    color:black;
    font-size: 13px;
}

.header {
    text-align: center;
    margin-bottom: 25px;
}

.urgent-banner {
    background: red;
    color: white;
    padding: 10px;
    font-size: 20px;
    font-weight: bold;
    margin-top: 15px;
}

.section {
    margin-bottom: 25px;
}

.section h3 {
    border-bottom: 1px solid #ccc;
    padding-bottom: 6px;
    margin-bottom: 12px;
}

.parts-table {
    width: 100%;
    border-collapse: collapse;
}

.parts-table th,
.parts-table td {
    border: 1px solid #ccc;
    padding: 8px;
}

.parts-table th {
    background: #f5f5f5;
}

.totals-section {
    margin-top: 25px;
    text-align: right;
}

.final-amount {
    font-size: 24px;
    font-weight: bold;
    margin-top: 15px;
}

.summary-section {
    margin-top: 30px;
}

.qr-section {
    text-align: center;
    margin-top: 40px;
}

.page-break {
    page-break-before: always;
}

@media print {

    button,
    .btn,
    .print-hide {
        display: none ;
    }
}
